const startedAt = new Date().toISOString();
const missingVars = [];
if (!$env.TELEGRAM_BOT_TOKEN) missingVars.push('TELEGRAM_BOT_TOKEN');
if (!$env.TELEGRAM_CHAT_ID) missingVars.push('TELEGRAM_CHAT_ID');
if (missingVars.length > 0) throw new Error('Pre-hook FAIL: ' + missingVars.join(', '));
return [{ json: { startedAt, workflow: 'codebase-audit', ok: true } }];

const ctx = $('Pre-Hook: Valida Contesto').first().json;
const audit = $('Esegui Audit via API').first().json;
const endedAt = new Date().toISOString();
const durationMs = new Date(endedAt) - new Date(ctx.startedAt);

const scoreEmoji = audit.score >= 90 ? '✅' : audit.score >= 70 ? '⚠️' : '🔴';
const lines = [];
lines.push(`🔍 *Codebase Audit — ${new Date().toLocaleDateString('it-IT')}*`);
lines.push('');
lines.push(`*Score:* ${scoreEmoji} ${audit.score ?? '?'}/100`);
lines.push(`*File TS:* ${audit.totalFiles ?? '?'} (${audit.totalLines?.toLocaleString() ?? '?'} righe totali)`);
lines.push('');

// File grandi
const big = audit.filesOverThreshold ?? [];
if (big.length > 0) {
  lines.push(`*File >300 righe (${big.length}):*`);
  big.slice(0, 8).forEach(f => {
    const icon = f.lines > 1000 ? '🔴' : f.lines > 600 ? '🟠' : '🟡';
    const name = f.file.replace('src/', '');
    lines.push(`  ${icon} ${f.lines} — ${name}`);
  });
  if (big.length > 8) lines.push(`  ... e altri ${big.length - 8}`);
  lines.push('');
} else {
  lines.push('✅ Nessun file >300 righe');
  lines.push('');
}

// Circular deps
const circular = audit.circularDeps ?? [];
if (circular.length > 0) {
  lines.push(`🔴 *Circular deps: ${circular.length}*`);
} else {
  lines.push('✅ Nessuna circular dep');
}

// Tech debt
const debt = audit.techDebt ?? [];
if (debt.length > 0) {
  lines.push(`⚠️ *Tech debt: ${debt.length} TODO/FIXME*`);
} else {
  lines.push('✅ Nessun TODO/FIXME');
}

lines.push('');
lines.push(`_Durata: ${durationMs}ms_`);

return [{ json: { report: lines.join('\n'), score: audit.score, endedAt, durationMs } }];

const r = $input.first().json;
const log = { workflow: 'codebase-audit', score: r.score, durationMs: r.durationMs, loggedAt: new Date().toISOString() };
console.log('[POST-HOOK codebase-audit]', JSON.stringify(log));
return [{ json: log }];
